config.handler:
const boton = event.target;
const fila = boton.closest(".row");

if (!fila) return;

const inputFile = fila.querySelector('input[type="file"][data-cy="file-upload-button"]');
if (inputFile) inputFile.click();

const boton = event.target;
const fila = boton.closest(".row");

if (!fila) return;

const btnEliminar = fila.querySelector('[selector="GrdFile"] .fa-trash-alt');

if (btnEliminar) {
  btnEliminar.click();
} else {
  alert("No se encontró el botón de eliminar en esta fila.");
}
